import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.D5wUhsuj.js";const k=JSON.parse('{"title":"PHP Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/php.md","filePath":"guide/php.md"}'),t={name:"guide/php.md"};function p(l,s,r,h,o,d){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="php-management" tabindex="-1">PHP Management <a class="header-anchor" href="#php-management" aria-label="Permalink to &quot;PHP Management&quot;">​</a></h1><h2 id="version-policy" tabindex="-1">Version policy <a class="header-anchor" href="#version-policy" aria-label="Permalink to &quot;Version policy&quot;">​</a></h2><p>AidiPanel installs PHP 8.4 by default. PHP 8.2, 8.3, and 8.5 remain available on demand so a fresh server does not carry unused runtimes. The policy is stored in <code>/etc/aidipanel/php.conf</code>.</p><p>Every PHP site has its own PHP-FPM pool. Sites can therefore use different installed PHP versions without sharing a pool or Unix socket.</p><h2 id="list-and-install-versions" tabindex="-1">List and install versions <a class="header-anchor" href="#list-and-install-versions" aria-label="Permalink to &quot;List and install versions&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:list</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>php:list</code> distinguishes installed versions from versions that are supported but not yet installed.</p><h2 id="inspect-or-switch-a-site" tabindex="-1">Inspect or switch a site <a class="header-anchor" href="#inspect-or-switch-a-site" aria-label="Permalink to &quot;Inspect or switch a site&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The target version must already be installed. Switching recreates that site&#39;s pool and repoints its Nginx vhost; other sites keep their own pools.</p><div class="warning custom-block"><p class="custom-block-title">Test application compatibility</p><p>Check the site&#39;s error log and application immediately after a major-version switch. Plugins and dependencies can use APIs removed by newer PHP releases.</p></div><h2 id="per-site-runtime-settings" tabindex="-1">Per-site runtime settings <a class="header-anchor" href="#per-site-runtime-settings" aria-label="Permalink to &quot;Per-site runtime settings&quot;">​</a></h2><p>Open <strong>Sites → example.com → PHP Settings</strong> to manage supported values such as memory limit, upload size, execution time, input limits, OPcache, and session behavior. AidiPanel validates values before rebuilding the site&#39;s pool.</p><p>The low-level CLI command reapplies settings already saved for the selected site:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:settings</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --php</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Use the panel UI for normal edits rather than changing generated pool files by hand.</p><h2 id="restart-and-inspect-php-fpm" tabindex="-1">Restart and inspect PHP-FPM <a class="header-anchor" href="#restart-and-inspect-php-fpm" aria-label="Permalink to &quot;Restart and inspect PHP-FPM&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:restart</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Restarting one version affects every site currently assigned to that version. <code>php:info</code> reports its extensions, configuration paths, and service state.</p><h2 id="quick-reference" tabindex="-1">Quick reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick reference&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>php:list                                      list supported and installed versions</span></span>
<span class="line"><span>php:install  --version &lt;version&gt;              install a supported version</span></span>
<span class="line"><span>php:version  --domain &lt;domain&gt;                show a site&#39;s version</span></span>
<span class="line"><span>php:version  --domain &lt;domain&gt; --set &lt;version&gt; switch a site</span></span>
<span class="line"><span>php:settings --domain &lt;domain&gt; --php &lt;version&gt; apply saved per-site settings</span></span>
<span class="line"><span>php:restart  [--version &lt;version&gt;]            restart PHP-FPM</span></span>
<span class="line"><span>php:info     --version &lt;version&gt;              inspect a version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div>`,21)])])}const u=a(t,[["render",p]]);export{k as __pageData,u as default};
